/**
 * @summary Check handle availability
 */
export const getCheckHandleUrl = (params: CheckHandleParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/handles/check?${stringifiedParams}`
    : `/api/v1/handles/check`;
};

export const checkHandle = async (
  params: CheckHandleParams,
  options?: RequestInit,
): Promise<HandleCheckResult> => {
  return customFetch<HandleCheckResult>(getCheckHandleUrl(params), {
    ...options,
    method: "GET",
  });
};

